def spiral_order(m):
    result = []
    while m:
        result += m.pop(0)
        if m and m[0]:
            for row in m:
                result.append(row.pop(0))
        if m:
            result += m.pop()[::-1]
        if m and m[0]:
            for row in m[::-1]:
                result.append(row.pop(0))
    return result
